.darma-loader-darma-custom-454 {color: var(--loader-color, #be123c);
   height: 35px;
   aspect-ratio: 1;
   border: 3px solid currentColor;
   animation: darma-loader-darma-custom-454-l4 2s infinite;
}
@keyframes darma-loader-darma-custom-454-l4  {
  0% {aspect-ratio:1;
  border-radius:50px}
25% {aspect-ratio:2;
  border-radius:50px}
50% {aspect-ratio:2;
  border-radius:0}
75% {aspect-ratio:1;
  border-radius:0}
100%{aspect-ratio:1;
  border-radius:50px}
}

